		new("earlymodern_western_naval_officer_undress_frock", "frock", "a plain $colour naval officer's frock", "A plain $colour naval officer's frock is made principally from broadcloth, with its seams, edges, joins, and fastening points finished for regular wear. Its construction gives the frock the recognisable form and drape shown by its outward appearance.", SizeCategory.Normal, ItemQuality.Good, 1500, 190.0m, true, "broadcloth", ["Era / Early Modern Era", "Functions / Military Equipment", "Market / Clothing / Military Uniforms"], ["Holdable", "Destroyable_Clothing", "Wear_Long_Coat", "Armour_HeavyClothing", "Insulation_Strong", "Variable_FineColour"], "New Early Modern military-uniform prototype; used in 4 military outfit(s)."),
		new("medieval_buddhist_black_monastic_robe", "robe", "a black hemp monastic robe", "This black hemp monastic robe is a straight wrapped garment with close sleeves and a plain collar line. The hemp has a dry, matte surface, darkened into a sober black without decorative contrast. Its cut is practical and restrained, keeping the focus on length, folds, and simplicity.", SizeCategory.Normal, ItemQuality.Standard, 540.0, 18.0m, true, "hemp", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_buddhist_nun_robe", "robe", "a dark hemp nun robe", "This dark hemp nun robe is a plain wrapped garment with long sleeves and a full, modest body. The hemp is firm and matte, with a darkened surface that hides wear better than pale cloth. Its lines are simple and practical, leaving the robe suited to layered monastic dress.", SizeCategory.Normal, ItemQuality.Standard, 560.0, 18.0m, true, "hemp", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_buddhist_patched_kasaya", "kasaya", "a patched cotton kasaya", "This patched cotton kasaya is a rectangular mantle built from many sewn panels. The cotton pieces are arranged in a deliberate grid, with seams forming a visible patchwork field across the cloth. It drapes over the shoulder and upper body, looking formal through pattern and construction rather than luxury.", SizeCategory.Normal, ItemQuality.Standard, 320.0, 24.0m, true, "cotton", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Mantle", "Destroyable_Clothing", "Insulation_Moderate", "Armour_HeavyClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_buddhist_travelling_mantle", "mantle", "a dark wool monastic travelling mantle", "This dark wool monastic travelling mantle is a broad outer cloth for sheltering a robe on the road. The wool is plain and serviceable, falling in wide folds over the shoulders and down the back. Its shape is practical and unornamented, closer to a traveller’s wrap than a formal temple mantle.", SizeCategory.Normal, ItemQuality.Standard, 760.0, 24.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Cloak_(Open)", "Destroyable_Clothing", "Insulation_Moderate", "Armour_HeavyClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_daoist_cloud_sleeved_robe", "robe", "a fine $colour cloud-sleeved robe", "This fine $colour cloud-sleeved robe is a silk ritual garment with broad sleeves and a loose cross-collar body. The sleeves spread widely from the arm, making the $colour silk fall in soft ceremonial folds. Its shape is more expansive than an ordinary robe, giving the garment a deliberate temple-formal presence.", SizeCategory.Normal, ItemQuality.Good, 680.0, 130.0m, true, "silk", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing", "Variable_FineColour"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_daoist_cross_collar_robe", "robe", "a dark cotton Daoist robe", "This dark cotton Daoist robe is cut with a cross-collar front, long sleeves, and a straight body. The cotton is plain and smooth, allowing the overlapping collar and tied closure to define the garment. It looks formal but not lavish, suited to a religious specialist rather than court display.", SizeCategory.Normal, ItemQuality.Standard, 520.0, 24.0m, true, "cotton", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_daoist_ritual_cap", "cap", "a black cloth ritual cap", "This black cloth ritual cap is a compact headpiece made from stiffened cotton panels. The shape is neat and angular, with a dark surface that sits close to the head. It is modest in scale but clearly formal, adding a precise finish to a robe without bright decoration.", SizeCategory.Small, ItemQuality.Standard, 90.0, 12.0m, true, "cotton", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Headwear"], ["Holdable", "Wear_Hat", "Destroyable_Clothing", "Insulation_Minor", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_black_klobuk", "klobuk", "a black veiled klobuk", "This black veiled klobuk combines a firm dark cap with a hanging veil that falls around the back and sides. The wool is matte and close, with the veil softening the hard line of the cap. It frames the head in a severe, recognisable shape without relying on jewels or bright colour.", SizeCategory.Small, ItemQuality.Standard, 240.0, 18.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Headwear"], ["Holdable", "Wear_Hat", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_black_riassa", "riassa", "a black wool riassa", "This black wool riassa is a long outer robe with a loose body and broad, unhurried sleeves. The cloth is sober and dark, falling from the shoulders in a straight vertical line. Its construction is plain but ample, giving the wearer a formal clerical outline without bright trimming.", SizeCategory.Normal, ItemQuality.Standard, 850.0, 30.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_epimanikia", "epimanikia", "a pair of $colour silk epimanikia", "These $colour silk epimanikia are fitted cuffs made to wrap around the lower sleeves. The silk panels are small but carefully shaped, with ties or narrow bands visible at the inner wrist. Their $colour surface gives a bright, formal finish to the hands and forearms.", SizeCategory.Small, ItemQuality.Good, 80.0, 50.0m, true, "silk", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Gloves"], ["Holdable", "Wear_Bracers", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing", "Variable_FineColour"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_epitrachelion", "epitrachelion", "a $colour silk epitrachelion", "This $colour silk epitrachelion is a paired stole joined at the neck and falling in two long panels down the front. The $colour silk has a formal sheen, broken by the fold where the fabric sits around the collar. Its length, symmetry, and careful edging make it distinct from an ordinary scarf.", SizeCategory.Small, ItemQuality.Good, 190.0, 70.0m, true, "silk", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Scarf", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing", "Variable_FineColour"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_kamilavkion", "kamilavkion", "a black felt kamilavkion", "This black felt kamilavkion is a stiff cylindrical cap with a flat crown and straight sides. The felt is dense and matte, holding the cap in a crisp, upright shape. Its severe black surface and clean silhouette give it a formal clerical character.", SizeCategory.Small, ItemQuality.Standard, 170.0, 20.0m, true, "felt", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Headwear"], ["Holdable", "Wear_Hat", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_monastic_mantle", "mantle", "a black wool monastic mantle", "This black wool monastic mantle is a wide outer wrap with enough breadth to cover the shoulders and much of the body. Its folds are heavy and dark, giving the garment a solemn, enclosing silhouette. The edges are simple and unembroidered, with visual weight supplied by the cloth itself.", SizeCategory.Normal, ItemQuality.Standard, 950.0, 34.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Mantle", "Destroyable_Clothing", "Insulation_Moderate", "Armour_HeavyClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_omophorion", "omophorion", "a fine white silk omophorion", "This fine white silk omophorion is a broad band made to lie over the shoulders and fall across the chest. The silk is pale, smooth, and substantial enough to hold its line over heavier vestments. Dark cross-like markings break the white field, giving the band an episcopal and ceremonial appearance.", SizeCategory.Small, ItemQuality.Good, 220.0, 120.0m, true, "silk", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Scarf", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_orarion", "orarion", "a $colour silk orarion", "This $colour silk orarion is a long narrow vestment meant to lie over the shoulder in a clear vertical line. The silk is smooth and formal, making the $colour surface catch light along its length. Its edges are straight and carefully finished, giving the band a precise liturgical appearance.", SizeCategory.Small, ItemQuality.Good, 130.0, 60.0m, true, "silk", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Scarf", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing", "Variable_FineColour"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_phelonion", "phelonion", "a fine $colour silk phelonion", "This fine $colour silk phelonion is a wide sleeveless outer vestment with a rounded fall from the shoulders. The front is cut to clear the hands while the back drops in a fuller sweep, showing the $colour silk in deep folds. Its form resembles a ceremonial mantle, but the head opening and continuous body give it a distinctive liturgical shape.", SizeCategory.Normal, ItemQuality.Good, 780.0, 170.0m, true, "silk", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Poncho", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing", "Variable_FineColour"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_sakkos", "sakkos", "a fine $colour silk sakkos", "This fine $colour silk sakkos is a square-cut outer vestment with broad sleeves and a structured, tunic-like body. The sides are visibly joined by small fastenings or ties, leaving the garment formal but not closely fitted. Its $colour silk and deliberate shape make it more imposing than an ordinary robe.", SizeCategory.Normal, ItemQuality.Good, 800.0, 210.0m, true, "silk", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing", "Variable_FineColour"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_sticharion", "sticharion", "a white linen sticharion", "This white linen sticharion is a long, straight liturgical robe with close sleeves and a pale, even surface. The linen falls cleanly to the feet, forming a bright underlayer beneath richer vestments. Its seams are tidy and restrained, emphasizing length and whiteness rather than decoration.", SizeCategory.Normal, ItemQuality.Good, 480.0, 40.0m, true, "linen", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_eastern_womens_monastic_veil", "veil", "a black monastic veil", "This black monastic veil is a plain wool head covering made to fall over the hair, shoulders, and upper back. The fabric is soft enough to fold close to the face but heavy enough to keep a dark, settled outline. It is modest and undecorated, with only the clean fall of cloth marking its form.", SizeCategory.Small, ItemQuality.Standard, 200.0, 12.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Headwear"], ["Holdable", "Wear_Veil", "Destroyable_Clothing", "Insulation_Minor", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_hindu_kaupina", "kaupina", "a plain cotton kaupina", "This plain cotton kaupina is a very simple loincloth made from a narrow length of white cloth. It is cut and folded for minimal coverage, with no decoration beyond the clean edges of the fabric. The cotton is light and practical, giving the garment an intentionally austere appearance.", SizeCategory.Small, ItemQuality.Standard, 90.0, 4.0m, true, "cotton", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Loincloth", "Destroyable_Clothing", "Insulation_Minor", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_hindu_ochre_ascetic_wrap", "wrap", "an ochre cotton ascetic wrap", "This ochre cotton ascetic wrap is a long rectangular cloth arranged to cover the body in loose folds. The cotton has a warm earth-coloured tone and a plain, unshaped surface. Its form is intentionally simple, relying on wrapping and tucking rather than tailoring.", SizeCategory.Normal, ItemQuality.Standard, 420.0, 14.0m, true, "cotton", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
