		new("medieval_jewish_tallit_katan", "tallit", "a white wool tallit katan", "This white wool tallit katan is a small four-cornered undergarment with a simple head opening and straight hanging panels. The wool is plain and pale, meant to sit beneath or between ordinary clothing layers. Fringes at the corners mark it clearly even though the body of the garment is spare.", SizeCategory.Small, ItemQuality.Standard, 230.0, 22.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Vest", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_latin_bishop_gloves", "gloves", "a pair of fine white liturgical gloves", "These fine white liturgical gloves are sewn from smooth silk with close fingers and neat wrist openings. The fabric has a pale sheen and lies cleanly against the hand when worn. Their finish is more delicate than working gloves, with the emphasis on spotless cloth and careful seams.", SizeCategory.Small, ItemQuality.Good, 90.0, 80.0m, true, "silk", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Gloves"], ["Holdable", "Wear_Gloves", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_latin_bishop_mitre", "mitre", "a fine white silk mitre", "This fine white silk mitre is a tall folded headpiece with two stiffened peaks rising above the brow. The silk is pale and smooth, with carefully joined seams holding the upright form. Narrow hanging bands fall from the back, making the headwear unmistakably formal without adding other carried objects.", SizeCategory.Small, ItemQuality.Good, 160.0, 140.0m, true, "silk", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Headwear"], ["Holdable", "Wear_Hat", "Destroyable_Clothing", "Insulation_Minor", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_latin_black_cowl", "cowl", "a black wool cowl", "This black wool cowl is a heavy hooded overgarment made to fall in a single dark mass around the shoulders. The hood is deep, the body loose, and the hem broad enough to drape over a habit beneath it. Its surface is plain and matte, with only the weight of the wool and the shadow of the hood giving it emphasis.", SizeCategory.Normal, ItemQuality.Standard, 650.0, 18.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Cloak_(Closed)", "Destroyable_Clothing", "Insulation_Strong", "Armour_HeavyClothing"], "Early Modern admission of an exact Medieval clothing definition."),
