		new("medieval_shinto_miko_red_hakama", "hakama", "a pair of red shrine hakama", "These red shrine hakama are broad pleated trousers made to fall in long, straight folds. The hemp cloth is dyed a clear red, making the lower garment stand out sharply beneath a white kosode. Their pleats and fullness give them a formal shrine-service outline while remaining practical to move in.", SizeCategory.Normal, ItemQuality.Standard, 460.0, 28.0m, true, "hemp", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Legwear"], ["Holdable", "Wear_Trousers", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_shinto_miko_white_kosode", "kosode", "a white hemp shrine kosode", "This white hemp shrine kosode is a short-sleeved robe with a straight wrapped front and narrow body. The hemp is pale, clean, and simply finished, showing little beyond the collar line and sleeve openings. It forms a modest upper layer for shrine service rather than a fashionable court garment.", SizeCategory.Normal, ItemQuality.Standard, 420.0, 24.0m, true, "hemp", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_shinto_priest_eboshi", "eboshi", "a black lacquered eboshi", "This black lacquered eboshi is a tall, folded headpiece with a crisp upright silhouette. The silk body is stiffened and darkened to a smooth black surface, keeping its shape above the brow. It looks formal and courtly, pairing with shrine robes without needing additional ornament.", SizeCategory.Small, ItemQuality.Good, 110.0, 38.0m, true, "silk", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Headwear"], ["Holdable", "Wear_Hat", "Destroyable_Clothing", "Insulation_Minor", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_shinto_priest_hakama", "hakama", "a pair of white shrine hakama", "These white shrine hakama are broad pleated trousers with a full, skirt-like fall. The hemp cloth is pale and crisp, holding the pleats in clean vertical lines. Their breadth and colour make them visibly ceremonial rather than ordinary work hakama.", SizeCategory.Normal, ItemQuality.Good, 480.0, 34.0m, true, "hemp", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Legwear"], ["Holdable", "Wear_Trousers", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_shinto_white_joe_robe", "jōe", "a white hemp jōe robe", "This white hemp jōe robe is a pale ceremonial garment with a straight body and broad, courtly sleeves. The hemp is clean and carefully finished, giving the robe a crisp surface despite its simple colour. Its shape recalls formal court dress, but the lack of pattern keeps it restrained and shrine-focused.", SizeCategory.Normal, ItemQuality.Good, 520.0, 42.0m, true, "hemp", ["Market / Clothing / Luxury Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_steppe_ritual_felt_coat", "coat", "a felt-lined ritual coat", "This felt-lined ritual coat is a long front-opening garment with loose sleeves and a practical steppe cut. Dense felt gives it body and warmth, while the outer surface remains plain enough to resemble travelling clothing. Its ritual character comes from its deliberate use as a special outer layer rather than from metal fittings or carried objects.", SizeCategory.Normal, ItemQuality.Standard, 1100.0, 34.0m, true, "felt", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Long_Coat", "Destroyable_Clothing", "Insulation_Strong", "Armour_HeavyClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_steppe_ritual_fur_cap", "cap", "a fur-trimmed ritual cap", "This fur-trimmed ritual cap is a warm headpiece with a soft crown and a thick band around the brow. The fur gives the cap a rough, animal-textured edge, contrasting with the simpler cloth or felt of the crown. It is visually suited to cold open country and to a specialist set apart by distinctive winter headwear.", SizeCategory.Small, ItemQuality.Standard, 220.0, 24.0m, true, "fur", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Headwear"], ["Holdable", "Wear_Hat", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_steppe_ritual_sash", "sash", "a braided wool ritual sash", "This braided wool ritual sash is a sturdy belt-like length of woven cloth with a visibly twisted structure. Its surface is rough and practical, with ends that hang plainly once tied. It adds a marked band across a robe or coat without claiming pockets, tools, or other unsupported functions.", SizeCategory.Small, ItemQuality.Standard, 190.0, 12.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Belts"], ["Holdable", "Wear_Sash", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_sufi_coarse_wool_cloak", "cloak", "a coarse wool Sufi cloak", "This coarse wool Sufi cloak is a heavy open wrap with a rough, plainly woven surface. It falls from the shoulders in uneven dark folds, large enough to cover a patched robe or plain qamis beneath. The cloak is austere rather than elegant, with a practical weight and little concern for polish.", SizeCategory.Normal, ItemQuality.Standard, 980.0, 22.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Cloak_(Open)", "Destroyable_Clothing", "Insulation_Moderate", "Armour_HeavyClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_sufi_felt_cap", "cap", "a plain felt dervish cap", "This plain felt dervish cap is a simple, close head covering shaped from dense felt. Its sides are unadorned, and the crown is rounded without embroidery or metal fittings. The material gives it a soft but durable outline suited to rough travel or simple lodgings.", SizeCategory.Small, ItemQuality.Standard, 140.0, 10.0m, true, "felt", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Headwear"], ["Holdable", "Wear_Hat", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_sufi_patched_khirqa", "khirqa", "a patched wool khirqa", "This patched wool khirqa is a loose robe assembled from visibly different pieces of worn cloth. The patches vary in tone and texture, but the whole garment keeps a roughly ordered robe shape with long sleeves and a full body. It looks intentionally poor and mended, using its roughness as its most visible feature.", SizeCategory.Normal, ItemQuality.Standard, 780.0, 18.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Bodywear"], ["Holdable", "Wear_Robe", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
		new("medieval_sufi_wool_sash", "sash", "a coarse wool Sufi sash", "This coarse wool Sufi sash is a plain length of cloth meant to bind a robe at the waist. The wool is rough, dark, and slightly uneven, with frayed-looking ends left visible. It is more severe than decorative, adding a practical horizontal line to otherwise loose clothing.", SizeCategory.Small, ItemQuality.Standard, 180.0, 6.0m, true, "wool", ["Market / Clothing / Standard Clothing", "Functions / Worn Items / Belts"], ["Holdable", "Wear_Sash", "Destroyable_Clothing", "Insulation_Moderate", "Armour_LightClothing"], "Early Modern admission of an exact Medieval clothing definition."),
